import React, { useState, useRef, useEffect } from 'react';

const SocialMediaPractice = () => {
  // 模拟数据 - 定义图片中需要标记的可疑区域
  const testCase = {
    image: "/images/socialmedia/1.jpg",
    dangerZones: [
      {
        id: 1,
        name: "Visible house number",
        description: "暴露了具体门牌号，可能被恶意利用",
        position: { x: 120, y: 80, width: 60, height: 30 } // 示例坐标，需根据实际图片调整
      },
      {
        id: 2,
        name: "Geotag location",
        description: "显示了精确的地理位置标签",
        position: { x: 200, y: 180, width: 40, height: 40 }
      }
    ]
  };

  const [userSelections, setUserSelections] = useState([]);
  const [phase, setPhase] = useState('selection'); // 'selection' | 'marking' | 'result'
  const [feedback, setFeedback] = useState('');
  const imageRef = useRef(null);
  const [imageSize, setImageSize] = useState({ width: 0, height: 0 });

  // 检测图片加载后获取实际尺寸
  useEffect(() => {
    if (imageRef.current) {
      const updateSize = () => {
        setImageSize({
          width: imageRef.current.offsetWidth,
          height: imageRef.current.offsetHeight
        });
      };
      
      imageRef.current.addEventListener('load', updateSize);
      return () => imageRef.current?.removeEventListener('load', updateSize);
    }
  }, []);

  // 处理用户初始选择
  const handleInitialChoice = (choice) => {
    if (choice === 'not_safe') {
      setPhase('marking');
    } else {
      setFeedback(choice === 'safe' 
        ? "❌ 不正确！这张图片包含隐私风险" 
        : "🤔 请仔细检查图片中的门牌号和地理位置");
    }
  };

  // 处理图片点击（标记可疑区域）
  const handleImageClick = (e) => {
    if (phase !== 'marking') return;
    
    const rect = e.target.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    
    // 检查点击是否在危险区域内
    const clickedZone = testCase.dangerZones.find(zone => {
      return x >= zone.position.x && 
             x <= zone.position.x + zone.position.width &&
             y >= zone.position.y && 
             y <= zone.position.y + zone.position.height;
    });

    if (clickedZone && !userSelections.includes(clickedZone.id)) {
      setUserSelections([...userSelections, clickedZone.id]);
    }
  };

  // 提交标记结果
  const handleSubmitMarks = () => {
    const allFound = testCase.dangerZones.every(zone => 
      userSelections.includes(zone.id)
    );
    
    if (allFound) {
      setFeedback("✅ 完美！你成功识别了所有隐私风险");
    } else {
      const missedZones = testCase.dangerZones
        .filter(zone => !userSelections.includes(zone.id))
        .map(zone => zone.name);
      
      setFeedback(`⚠️ 你遗漏了：${missedZones.join('、')}`);
    }
    setPhase('result');
  };

  // 重置练习
  const resetPractice = () => {
    setUserSelections([]);
    setPhase('selection');
    setFeedback('');
  };

  return (
    <div className="content-card">
      <h2 style={styles.header}>📱 社交媒体隐私练习</h2>

      {/* 第一阶段：初始选择 */}
      {phase === 'selection' && (
        <div style={styles.bubble}>
          <span style={styles.bot}>🤖</span> 
          这张社交媒体图片安全吗？请先做出你的判断：
          
          <div style={styles.options}>
            <button 
              onClick={() => handleInitialChoice('safe')}
              style={styles.optionButton}
            >
              ✅ 安全
            </button>
            <button 
              onClick={() => handleInitialChoice('not_safe')}
              style={styles.optionButton}
            >
              ⚠️ 不安全
            </button>
          </div>
        </div>
      )}

      {/* 图片展示区域 */}
      <div style={styles.imageContainer}>
        <img
          ref={imageRef}
          src={testCase.image}
          alt="社交媒体示例"
          style={styles.image}
          onClick={handleImageClick}
        />
        
        {/* 标记危险区域（可视化） */}
        {phase === 'marking' && testCase.dangerZones.map(zone => (
          <div
            key={zone.id}
            style={{
              position: 'absolute',
              left: `${zone.position.x}px`,
              top: `${zone.position.y}px`,
              width: `${zone.position.width}px`,
              height: `${zone.position.height}px`,
              border: userSelections.includes(zone.id) 
                ? '3px solid #4CAF50' 
                : '2px dashed #FF5722',
              backgroundColor: userSelections.includes(zone.id) 
                ? 'rgba(76, 175, 80, 0.3)' 
                : 'transparent',
              pointerEvents: 'none'
            }}
          />
        ))}
      </div>

      {/* 第二阶段：标记危险区域 */}
      {phase === 'marking' && (
        <div style={styles.bubble}>
          <span style={styles.bot}>🤖</span> 
          请点击图片中暴露隐私的区域（已标记 {userSelections.length}/{testCase.dangerZones.length}）
          
          <div style={styles.zoneList}>
            {testCase.dangerZones.map(zone => (
              <div key={zone.id} style={styles.zoneItem}>
                {userSelections.includes(zone.id) ? '✅' : '◻️'} 
                {zone.name}
              </div>
            ))}
          </div>
          
          <button
            onClick={handleSubmitMarks}
            style={styles.submitButton}
            disabled={userSelections.length === 0}
          >
            提交标记
          </button>
        </div>
      )}

      {/* 第三阶段：结果显示 */}
      {phase === 'result' && (
        <div style={styles.bubble}>
          <span style={styles.bot}>🤖</span> 
          {feedback}
          
          <div style={styles.dangerDetails}>
            {testCase.dangerZones.map(zone => (
              <div key={zone.id} style={styles.detailItem}>
                <h4>⚠️ {zone.name}</h4>
                <p>{zone.description}</p>
              </div>
            ))}
          </div>
          
          <button
            onClick={resetPractice}
            style={styles.tryAgainButton}
          >
            再试一次
          </button>
        </div>
      )}
    </div>
  );
};

const styles = {
  header: {
    textAlign: 'center',
    color: '#00796b',
    marginBottom: '1.5em'
  },
  bubble: {
    backgroundColor: '#e3f2fd',
    padding: '1em',
    borderRadius: '12px',
    margin: '1em 0',
    borderLeft: '4px solid #2196F3'
  },
  bot: {
    fontWeight: 'bold',
    marginRight: '0.5em'
  },
  imageContainer: {
    position: 'relative',
    margin: '1.5em 0',
    cursor: 'crosshair'
  },
  image: {
    width: '100%',
    maxWidth: '500px',
    borderRadius: '8px',
    border: '1px solid #b0bec5'
  },
  options: {
    display: 'flex',
    gap: '1em',
    marginTop: '1em'
  },
  optionButton: {
    flex: 1,
    padding: '0.8em',
    borderRadius: '8px',
    border: 'none',
    background: '#e3f2fd',
    cursor: 'pointer',
    fontWeight: 'bold',
    transition: 'all 0.2s',
    ':hover': {
      background: '#bbdefb'
    }
  },
  zoneList: {
    margin: '1em 0',
    paddingLeft: '1em'
  },
  zoneItem: {
    margin: '0.5em 0'
  },
  dangerDetails: {
    marginTop: '1em',
    background: '#fff3e0',
    padding: '1em',
    borderRadius: '8px'
  },
  detailItem: {
    marginBottom: '1em'
  },
  submitButton: {
    width: '100%',
    padding: '0.8em',
    background: '#4CAF50',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    marginTop: '1em',
    cursor: 'pointer',
    ':disabled': {
      background: '#cccccc'
    }
  },
  tryAgainButton: {
    width: '100%',
    padding: '0.8em',
    background: 'transparent',
    color: '#2196F3',
    border: '1px solid #2196F3',
    borderRadius: '8px',
    marginTop: '1em',
    cursor: 'pointer'
  }
};

export default SocialMediaPractice;
